### Scheduler Structure
\`\`\`rust
use std::collections::{VecDeque, HashMap};
use tokio::sync::mpsc;

pub struct BenchmarkScheduler {
    /// Configuration
    config: SchedulerConfig,

    /// Queue of workers needing benchmarks (priority queue)
    pending_queue: VecDeque<BenchmarkRequest>,

    /// Currently running benchmarks
    running: HashMap<WorkerId, BenchmarkRun>,

    /// Channel for manual trigger requests
    trigger_rx: mpsc::Receiver<BenchmarkTrigger>,

    /// Worker pool reference (for reservation)
    worker_pool: Arc<WorkerPool>,

    /// Telemetry store reference (for idle detection)
    telemetry_store: Arc<TelemetryStore>,

    /// SpeedScore storage
    speedscore_store: Arc<TelemetryStorage>,
}

pub struct SchedulerConfig {
    pub min_interval: Duration,        // Default: 6 hours
    pub max_age: Duration,             // Default: 24 hours
    pub idle_cpu_threshold: f64,       // Default: 20%
    pub max_concurrent: usize,         // Default: 1
    pub drift_threshold_pct: f64,      // Default: 20%
    pub benchmark_timeout: Duration,   // Default: 5 minutes
}

#[derive(Debug)]
pub struct BenchmarkRequest {
    pub worker_id: WorkerId,
    pub priority: BenchmarkPriority,
    pub requested_at: DateTime<Utc>,
    pub reason: BenchmarkReason,
}

#[derive(Debug, PartialEq, Eq, PartialOrd, Ord)]
pub enum BenchmarkPriority {
    High,    // New workers, manual trigger
    Normal,  // Scheduled re-benchmark
    Low,     // Drift detection
}

#[derive(Debug)]
pub enum BenchmarkReason {
    NewWorker,
    StaleScore { age: Duration },
    ManualTrigger { user: String },
    DriftDetected { drift_pct: f64 },
    Scheduled,
}
