### Benchmark Executor
\`\`\`rust
pub struct BenchmarkExecutor {
    worker: Worker,
    timeout: Duration,
}

impl BenchmarkExecutor {
    pub async fn execute_all_benchmarks(&self) -> Result<SpeedScore> {
        info!(worker_id = %self.worker.id, "Executing benchmark suite");

        // Run benchmarks sequentially on worker via SSH
        let cpu_result = self.run_remote_benchmark("cpu").await?;
        let memory_result = self.run_remote_benchmark("memory").await?;
        let disk_result = self.run_remote_benchmark("disk").await?;
        let network_result = NetworkBenchmark::new(self.worker.clone(), 10)
            .run().await?;  // Network benchmark has special handling
        let compilation_result = self.run_remote_benchmark("compilation").await?;

        // Combine into SpeedScore
        let speedscore = SpeedScore::calculate(&BenchmarkResults {
            cpu: cpu_result,
            memory: memory_result,
            disk: disk_result,
            network: network_result,
            compilation: compilation_result,
        })?;

        Ok(speedscore)
    }

    async fn run_remote_benchmark(&self, benchmark_type: &str) -> Result<BenchmarkResult> {
        let command = format!("rch-benchmark run --type {} --format json", benchmark_type);

        let output = ssh_exec_timeout(
            &self.worker,
            &command,
            self.timeout,
        ).await?;

        let result: BenchmarkResult = serde_json::from_str(&output)?;
        Ok(result)
    }
}
