#[test]
fn test_queue_priority_ordering() {
    info!("TEST START: test_queue_priority_ordering");
    let mut scheduler = make_test_scheduler();

    // Enqueue in wrong order
    scheduler.enqueue(BenchmarkRequest {
        worker_id: "low".into(),
        priority: BenchmarkPriority::Low,
        ..Default::default()
    });
    scheduler.enqueue(BenchmarkRequest {
        worker_id: "high".into(),
        priority: BenchmarkPriority::High,
        ..Default::default()
    });
    scheduler.enqueue(BenchmarkRequest {
        worker_id: "normal".into(),
        priority: BenchmarkPriority::Normal,
        ..Default::default()
    });

    info!("INPUT: Enqueued Low, High, Normal workers");
    scheduler.pending_queue.make_contiguous().sort_by_key(|r| r.priority);

    let first = scheduler.pending_queue.pop_front().unwrap();
    info!("RESULT: First dequeued = {}", first.worker_id);
    assert_eq!(first.worker_id, "high");
    info!("VERIFY: High priority worker dequeued first");
    info!("TEST PASS: test_queue_priority_ordering");
}

#[test]
fn test_max_concurrent_limit() {
    info!("TEST START: test_max_concurrent_limit");
    let mut scheduler = make_test_scheduler();
    scheduler.config.max_concurrent = 2;

    // Start 2 benchmarks
    scheduler.running.insert("w1".into(), make_run("w1"));
    scheduler.running.insert("w2".into(), make_run("w2"));

    // Enqueue another
    scheduler.enqueue(make_request("w3"));

    info!("INPUT: 2 running (max=2), 1 in queue");
    let started_before = scheduler.running.len();
    scheduler.process_pending_queue().await;
    let started_after = scheduler.running.len();

    info!("RESULT: Running before={}, after={}", started_before, started_after);
    assert_eq!(started_before, started_after);
    assert_eq!(scheduler.pending_queue.len(), 1);
    info!("VERIFY: No new benchmark started (at max concurrent)");
    info!("TEST PASS: test_max_concurrent_limit");
}
