#[tokio::test]
async fn test_full_benchmark_cycle() {
    info!("TEST START: test_full_benchmark_cycle");
    let harness = TestHarness::new("benchmark_cycle").await;
    harness.require_workers(&["css"]).await;

    // Clear any existing scores
    harness.clear_speedscores().await;

    let scheduler = harness.create_benchmark_scheduler();

    info!("INPUT: Worker 'css' with no SpeedScore");

    // Should queue css for benchmark
    scheduler.check_workers_for_scheduling().await;
    assert_eq!(scheduler.pending_queue.len(), 1);
    info!("VERIFY: Worker queued for benchmark");

    // Process queue (will start benchmark)
    scheduler.process_pending_queue().await;
    assert_eq!(scheduler.running.len(), 1);
    info!("VERIFY: Benchmark started");

    // Wait for benchmark completion
    harness.wait_for_benchmark_completion("css", Duration::from_secs(120)).await;

    let score = harness.get_speedscore("css").await;
    info!("RESULT: SpeedScore = {:?}", score);
    assert!(score.is_some());
    assert!(score.unwrap().total > 0.0);
    info!("VERIFY: SpeedScore calculated and stored");
    info!("TEST PASS: test_full_benchmark_cycle");

    harness.cleanup().await;
}

#[tokio::test]
async fn test_manual_benchmark_trigger() {
    info!("TEST START: test_manual_benchmark_trigger");
    let harness = TestHarness::new("manual_trigger").await;
    harness.require_workers(&["css"]).await;

    // Give worker a recent score (shouldn't auto-benchmark)
    harness.set_speedscore("css", SpeedScore {
        total: 75.0,
        measured_at: Utc::now() - Duration::hours(1),
        ..Default::default()
    }).await;

    let scheduler = harness.create_benchmark_scheduler();

    info!("INPUT: Worker with 1-hour-old score, sending manual trigger");

    // Trigger manual benchmark
    scheduler.trigger_tx.send(BenchmarkTrigger {
        worker_id: "css".into(),
        user: "admin".into(),
    }).await.unwrap();

    // Should be queued despite recent score
    tokio::time::sleep(Duration::from_millis(100)).await;
    assert_eq!(scheduler.pending_queue.len(), 1);
    info!("VERIFY: Manual trigger queued despite recent score");
    info!("TEST PASS: test_manual_benchmark_trigger");

    harness.cleanup().await;
}
